@startuml
!theme plain

package "com" as com {
  package "dependency" as dependency {
    package "injection" as injection {
      class SimpleWizard {
        - tobacco : OldTobyTobacco
        + SimpleWizard()
        + smoke()
      }

      class AdvancedWizard {
        - tobacco : Tobacco
        + AdvancedWizard(tobacco : Tobacco)
        + smoke()
      }

      class GuiceWizard {
        - tobacco : Tobacco
        + GuiceWizard(tobacco : Tobacco)
        + smoke()
      }

      class App {
        + App()
        + main(args : String[])
      }

      class Wizard {
        + smoke()
      }

      class Tobacco {
        + Tobacco()
        + smoke(wizard : Wizard)
      }

      class RivendellTobacco {
        + RivendellTobacco()
      }

      class OldTobyTobacco {
        + OldTobyTobacco()
      }

      class SecondBreakfastTobacco {
        + SecondBreakfastTobacco()
      }

      AdvancedWizard ..|> Wizard
      GuiceWizard ..|> Wizard
      RivendellTobacco --|> Tobacco
      OldTobyTobacco --|> Tobacco
      SecondBreakfastTobacco --|> Tobacco

      SimpleWizard --> OldTobyTobacco : -tobacco
      AdvancedWizard --> Tobacco : -tobacco
      GuiceWizard --> Tobacco : -tobacco
      App --> OldTobyTobacco : -tobacco
    }
  }
}

@enduml
